import time, random
from openai import OpenAI, RateLimitError, APIStatusError, APITimeoutError

client = OpenAI(timeout=30.0, max_retries=0)

def call_llm(messages: list, model="gpt-4o-mini", max_retries=5) -> str:
    for attempt in range(max_retries):
        try:
            resp = client.chat.completions.create(model=model, messages=messages)
            return resp.choices[0].message.content
        except RateLimitError:
            wait = (2 ** attempt) + random.uniform(0, 1)  # exponential + jitter
            print(f"Rate limited. Waiting {wait:.1f}s...")
            time.sleep(min(wait, 60))
        except APITimeoutError:
            print(f"Timeout on attempt {attempt + 1}")
            time.sleep(2 ** attempt)
        except APIStatusError as e:
            if e.status_code >= 500:  # server error — retry
                time.sleep(2 ** attempt)
            else:
                raise  # 4xx is our fault — don't retry
    raise Exception("Max retries exceeded")

