import numpy as np
from collections import defaultdict

class NaiveBayesClassifier:
    def fit(self, X_text, y):
        self.classes_ = list(set(y))
        self.log_prior_ = {}
        self.log_likelihood_ = {}
        n = len(y)
        vocab = set(w for d in X_text for w in d.split())
        for c in self.classes_:
            docs = [X_text[i] for i in range(n) if y[i] == c]
            self.log_prior_[c] = np.log(len(docs) / n)
            word_counts = defaultdict(int)
            total = 0
            for doc in docs:
                for word in doc.split():
                    word_counts[word] += 1
                    total += 1
            # Laplace smoothing prevents zero probabilities
            self.log_likelihood_[c] = {
                w: np.log((word_counts[w] + 1) / (total + len(vocab)))
                for w in vocab
            }
            self.log_likelihood_[c]['__unk__'] = np.log(1 / (total + len(vocab)))

    def predict(self, text):
        scores = {}
        for c in self.classes_:
            scores[c] = self.log_prior_[c]
            for word in text.split():
                scores[c] += self.log_likelihood_[c].get(word, self.log_likelihood_[c]['__unk__'])
        return max(scores, key=scores.get)

