import asyncio
import openai
from dataclasses import dataclass

async_client = openai.AsyncOpenAI()

@dataclass
class LLMResult:
    prompt: str
    response: str | None
    error: str | None = None

async def call_with_limit(
    semaphore: asyncio.Semaphore,
    prompt: str,
    model: str = "gpt-4o-mini",
) -> LLMResult:
    """One LLM call, gated by a semaphore for rate limiting."""
    async with semaphore:  # blocks if too many concurrent calls
        try:
            resp = await async_client.chat.completions.create(
                model=model,
                messages=[{"role": "user", "content": prompt}],
            )
            return LLMResult(prompt=prompt, response=resp.choices[0].message.content)
        except openai.RateLimitError as e:
            return LLMResult(prompt=prompt, response=None, error=f"RateLimit: {e}")
        except Exception as e:
            return LLMResult(prompt=prompt, response=None, error=str(e))

async def batch_llm(
    prompts: list[str],
    max_concurrent: int = 10,
) -> list[LLMResult]:
    semaphore = asyncio.Semaphore(max_concurrent)
    tasks = [call_with_limit(semaphore, p) for p in prompts]
    return await asyncio.gather(*tasks)

