import functools
import time
import random
from typing import Type

def retry(
    max_attempts: int = 3,
    exceptions: tuple[Type[Exception], ...] = (Exception,),
    base_delay: float = 1.0,
    max_delay: float = 60.0,
):
    """Retry a function with exponential backoff on specified exceptions."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt == max_attempts:
                        raise  # out of retries — re-raise the last error
                    delay = min(base_delay * (2 ** (attempt - 1)), max_delay)
                    jitter = random.uniform(0, delay * 0.1)  # prevent thundering herd
                    print(f"[retry] {func.__name__} failed ({e}). "
                          f"Attempt {attempt}/{max_attempts}. "
                          f"Retrying in {delay + jitter:.1f}s")
                    time.sleep(delay + jitter)
        return wrapper
    return decorator

