import numpy as np

def gini(y):
    classes, counts = np.unique(y, return_counts=True)
    probs = counts / counts.sum()
    return 1 - np.sum(probs ** 2)

def entropy(y):
    classes, counts = np.unique(y, return_counts=True)
    probs = counts / counts.sum()
    return -np.sum(probs * np.log2(probs + 1e-12))

def information_gain(y_parent, y_left, y_right):
    n = len(y_parent)
    w_l = len(y_left) / n
    w_r = len(y_right) / n
    return entropy(y_parent) - (w_l * entropy(y_left) + w_r * entropy(y_right))

y = np.array([0, 0, 1, 1, 1, 0, 1, 0])
print(f'Gini: {gini(y):.4f}')        # 0.5 = maximum impurity
print(f'Entropy: {entropy(y):.4f}')  # ~1.0 = maximum entropy

y_left  = np.array([0, 0, 0])
y_right = np.array([1, 1, 1, 1, 0])
print(f'Info Gain: {information_gain(y, y_left, y_right):.4f}')

