def transcribe(audio_path: str) -> dict:
    t0 = time.time()
    segments, info = model.transcribe(
        audio_path,
        beam_size=5,
        word_timestamps=True,
        vad_filter=True,           # skip silence automatically
        vad_parameters={'min_silence_duration_ms': 500}
    )
    result = []
    for seg in segments:
        result.append({
            'start': round(seg.start, 3),
            'end':   round(seg.end, 3),
            'text':  seg.text.strip(),
            'words': [{'word': w.word, 'start': w.start,
                        'end': w.end, 'prob': round(w.probability, 3)}
                       for w in (seg.words or [])]
        })
    elapsed = time.time() - t0
    rtf = elapsed / info.duration  # Real-Time Factor < 1.0 = faster than real-time
    print(f'RTF: {rtf:.2f}x | Lang: {info.language} ({info.language_probability:.0%})')
    return {'segments': result, 'language': info.language}

