import torch.nn as nn

# ✅ CORRECT order: Linear → BN → ReLU → Dropout
def correct_block(in_f: int, out_f: int) -> nn.Sequential:
    return nn.Sequential(
        nn.Linear(in_f, out_f),
        nn.BatchNorm1d(out_f),  # normalize BEFORE activation
        nn.ReLU(),
        nn.Dropout(0.3),        # drop AFTER activation
    )

# ❌ WRONG: Dropout before BN disrupts running statistics
def wrong_block(in_f: int, out_f: int) -> nn.Sequential:
    return nn.Sequential(
        nn.Linear(in_f, out_f),
        nn.Dropout(0.3),        # distorts mean/var that BN will compute
        nn.BatchNorm1d(out_f),
        nn.ReLU(),
    )

# CNN example with BatchNorm2d
class ConvBlock(nn.Module):
    def __init__(self, in_c: int, out_c: int):
        super().__init__()
        self.block = nn.Sequential(
            nn.Conv2d(in_c, out_c, kernel_size=3, padding=1, bias=False),
            # bias=False: BN already adds a bias via beta parameter
            nn.BatchNorm2d(out_c),
            nn.ReLU(inplace=True),
            # Spatial Dropout: drops entire feature maps (stronger regularization)
            nn.Dropout2d(0.1),
        )
    def forward(self, x):
        return self.block(x)

import torch
import torch.nn as nn


class DoubleConv(nn.Module):
    """Two consecutive Conv2d -> BatchNorm -> ReLU blocks (the basic U-Net unit)."""
    def __init__(self, in_ch: int, out_ch: int):
        super().__init__()
        self.block = nn.Sequential(
            nn.Conv2d(in_ch, out_ch, kernel_size=3, padding=1, bias=False),
            nn.BatchNorm2d(out_ch),
            nn.ReLU(inplace=True),
            nn.Conv2d(out_ch, out_ch, kernel_size=3, padding=1, bias=False),
            nn.BatchNorm2d(out_ch),
            nn.ReLU(inplace=True),
        )

    def forward(self, x):
        return self.block(x)


class Down(nn.Module):
    """Encoder step: MaxPool2d then DoubleConv (halves spatial dims)."""
    def __init__(self, in_ch: int, out_ch: int):
        super().__init__()
        self.pool_conv = nn.Sequential(
            nn.MaxPool2d(2),
            DoubleConv(in_ch, out_ch),
        )

    def forward(self, x):
        return self.pool_conv(x)


class Up(nn.Module):
    """
    Decoder step: bilinear upsample, concatenate skip features, then DoubleConv.
    in_ch is the sum of upsampled channels + skip channels.
    """
    def __init__(self, in_ch: int, out_ch: int):
        super().__init__()
        self.up   = nn.Upsample(scale_factor=2, mode='bilinear', align_corners=True)
        self.conv = DoubleConv(in_ch, out_ch)

    def forward(self, x, skip):
        x = self.up(x)
        x = torch.cat([skip, x], dim=1)
        return self.conv(x)

