from openai import OpenAI
from dataclasses import dataclass, field
import json, logging, time

logger = logging.getLogger(__name__)
client = OpenAI()

@dataclass
class AgentState:
    goal: str
    messages: list = field(default_factory=list)
    step: int = 0
    tool_calls: int = 0
    start_time: float = field(default_factory=time.time)

class ProductionAgent:
    def __init__(self, tools, tool_fns, model='gpt-4o',
                 max_steps=25, max_tool_calls=60):
        self.tools, self.tool_fns = tools, tool_fns
        self.model, self.max_steps = model, max_steps
        self.max_tool_calls = max_tool_calls

    def run(self, goal: str) -> str:
        state = AgentState(goal=goal)
        state.messages = [
            {'role': 'system', 'content': 'You are an expert agent. Use tools methodically. Think before acting.'},
            {'role': 'user', 'content': goal}
        ]

        for step in range(self.max_steps):
            state.step = step
            if state.tool_calls >= self.max_tool_calls:
                logger.warning('Tool call budget exhausted')
                break

            resp = client.chat.completions.create(
                model=self.model, messages=state.messages,
                tools=self.tools, tool_choice='auto'
            )
            msg = resp.choices[0].message
            state.messages.append(msg)

            if resp.choices[0].finish_reason == 'stop':
                logger.info(f'Completed in {step+1} steps, {state.tool_calls} tool calls')
                return msg.content

            for tc in msg.tool_calls or []:
                result = self._exec(tc)
                state.messages.append({
                    'role': 'tool', 'tool_call_id': tc.id, 'content': result
                })
                state.tool_calls += 1

        return state.messages[-1].get('content', 'Max steps reached.')

    def _exec(self, tc) -> str:
        logger.info(f'  → {tc.function.name}({tc.function.arguments[:60]}...)')
        try:
            args = json.loads(tc.function.arguments)
            fn   = self.tool_fns.get(tc.function.name)
            if not fn: return json.dumps({'error': f'Unknown tool: {tc.function.name}'})
            result = fn(**args)
            return json.dumps(result) if not isinstance(result, str) else result
        except Exception as e:
            logger.error(f'Tool {tc.function.name} failed: {e}')
            return json.dumps({'error': str(e), 'tool': tc.function.name})

