from transformers import AutoTokenizer, AutoModelForCausalLM
import torch

GUARD_MODEL = 'meta-llama/LlamaGuard-7b'
tokenizer = AutoTokenizer.from_pretrained(GUARD_MODEL)
model = AutoModelForCausalLM.from_pretrained(
    GUARD_MODEL, torch_dtype=torch.bfloat16, device_map='auto'
)

def classify_safety(user_message: str, assistant_response: str) -> dict:
    """Returns safe/unsafe + violated category."""
    chat = [
        {"role": "user",      "content": user_message},
        {"role": "assistant", "content": assistant_response},
    ]
    input_ids = tokenizer.apply_chat_template(
        chat, return_tensors='pt'
    ).to(model.device)

    with torch.no_grad():
        out = model.generate(
            input_ids, max_new_tokens=20, pad_token_id=tokenizer.eos_token_id
        )
    decoded = tokenizer.decode(out[0][input_ids.shape[-1]:], skip_special_tokens=True).strip()

    if decoded.startswith('safe'):
        return {'safe': True, 'category': None}
    else:
        # e.g. 'unsafe\nS1' — S1=Violence, S2=Non-Violent Crimes, etc.
        parts = decoded.split()
        category = parts[1] if len(parts) > 1 else 'unknown'
        return {'safe': False, 'category': category}

# Wrap your LLM call
def safe_respond(user_msg: str, llm_response: str) -> str:
    result = classify_safety(user_msg, llm_response)
    if not result['safe']:
        return f'I cannot provide that response. (Category: {result["category"]})'
    return llm_response

