from scipy import stats
import numpy as np
from dataclasses import dataclass
from typing import Dict, List

@dataclass
class DriftReport:
    feature: str
    ks_stat: float
    p_value: float
    drifted: bool

class ModelMonitor:
    """Lightweight monitor: stores baseline stats and runs drift checks."""

    def __init__(self, ks_threshold: float = 0.05):
        self.ks_threshold = ks_threshold
        self.baseline: Dict[str, np.ndarray] = {}
        self.prediction_log: List[float] = []

    def set_baseline(self, data: Dict[str, np.ndarray]):
        self.baseline = {k: np.array(v) for k, v in data.items()}
        print(f'Baseline set for: {list(self.baseline.keys())}')

    def log_predictions(self, predictions: List[float]):
        self.prediction_log.extend(predictions)

    def check_feature_drift(self, current: Dict[str, np.ndarray]) -> List[DriftReport]:
        reports = []
        for feat, values in current.items():
            if feat not in self.baseline:
                continue
            stat, pval = stats.ks_2samp(self.baseline[feat], np.array(values))
            reports.append(DriftReport(
                feature=feat, ks_stat=round(stat, 4),
                p_value=round(pval, 6), drifted=pval < self.ks_threshold
            ))
        return reports

    def prediction_health(self, expected_mean: float, tolerance: float = 0.10):
        if not self.prediction_log:
            return {'status': 'no data'}
        current_mean = float(np.mean(self.prediction_log))
        deviation = abs(current_mean - expected_mean)
        return {
            'current_mean': round(current_mean, 4),
            'expected_mean': expected_mean,
            'deviation': round(deviation, 4),
            'alert': deviation > tolerance
        }

# --- Demo ---
np.random.seed(42)
monitor = ModelMonitor()
monitor.set_baseline({'age': np.random.normal(35, 10, 2000)})
monitor.log_predictions(np.random.binomial(1, 0.45, 500).tolist())

reports = monitor.check_feature_drift({'age': np.random.normal(40, 11, 400)})
for r in reports:
    status = 'DRIFTED' if r.drifted else 'OK'
    print(f'{r.feature}: KS={r.ks_stat}, p={r.p_value} -> {status}')

health = monitor.prediction_health(expected_mean=0.30)
print('Prediction health:', health)

