# ---- Agent loop ----
def run_agent(goal: str, max_steps: int = 6) -> str:
    messages = [
        {"role": "system", "content": (
            "You are an autonomous agent. You will be given a goal. "
            "Use the tools available to you to achieve it step by step. "
            "When the goal is fully achieved, call no more tools and respond with your final answer."
        )},
        {"role": "user", "content": f"Goal: {goal}"}
    ]

    for step in range(max_steps):
        print(f"\n--- Step {step + 1} ---")
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=TOOL_SCHEMAS,
            tool_choice="auto"
        )
        msg = response.choices[0].message
        messages.append(msg)  # add assistant turn to history

        # If the model wants to call a tool
        if msg.tool_calls:
            for tc in msg.tool_calls:
                fn_name = tc.function.name
                fn_args = json.loads(tc.function.arguments)
                print(f"  Tool call: {fn_name}({fn_args})")
                result = TOOLS[fn_name](**fn_args)
                print(f"  Result: {result}")
                messages.append({
                    "role": "tool",
                    "tool_call_id": tc.id,
                    "content": result
                })
        else:
            # No tool call — agent has finished
            print(f"  Final answer: {msg.content}")
            return msg.content

    return "Max steps reached without finishing."

# Run it
