from openai import OpenAI

client = OpenAI()

def reflect_and_improve(goal: str, draft: str, max_revisions: int = 2) -> str:
    """Ask the model to critique its own draft and revise if needed."""
    for revision in range(max_revisions):
        critique_prompt = [
            {"role": "system", "content": "You are a strict reviewer. Identify any errors, gaps, or missing steps in the answer below. If the answer is complete and correct, respond with exactly: LGTM"},
            {"role": "user", "content": f"Goal: {goal}\n\nDraft answer:\n{draft}"}
        ]
        critique = client.chat.completions.create(
            model="gpt-4o-mini", messages=critique_prompt
        ).choices[0].message.content

        print(f"  [Revision {revision+1}] Critique: {critique[:120]}")

        if "LGTM" in critique:
            print("  Self-critique passed.")
            return draft

        # Revise based on critique
        revise_prompt = [
            {"role": "system", "content": "Revise the following answer based on the critique provided."},
            {"role": "user", "content": f"Goal: {goal}\n\nDraft:\n{draft}\n\nCritique:\n{critique}"}
        ]
        draft = client.chat.completions.create(
            model="gpt-4o-mini", messages=revise_prompt
        ).choices[0].message.content
        print(f"  Revised answer: {draft[:120]}...")

    return draft

