from collections import defaultdict
from dataclasses import dataclass, field
from typing import List

@dataclass
class KnowledgeGraph:
    # entity_name -> list of (relation, target)
    edges: dict = field(default_factory=lambda: defaultdict(list))
    # entity_name -> metadata dict
    nodes: dict = field(default_factory=dict)

    def add_entity(self, name: str, etype: str, desc: str):
        self.nodes[name] = {"type": etype, "description": desc}

    def add_relationship(self, source: str, relation: str, target: str):
        self.edges[source].append({"relation": relation, "target": target})

    def neighbors(self, entity: str, depth: int = 2) -> List[str]:
        """BFS up to `depth` hops."""
        visited, queue = set(), [(entity, 0)]
        while queue:
            node, d = queue.pop(0)
            if node in visited or d > depth:
                continue
            visited.add(node)
            for edge in self.edges.get(node, []):
                queue.append((edge["target"], d + 1))
        return list(visited - {entity})

    def subgraph_context(self, entity: str, depth: int = 2) -> str:
        """Return all facts within `depth` hops as plain text."""
        related = self.neighbors(entity, depth)
        lines = []
        for n in [entity] + related:
            for edge in self.edges.get(n, []):
                lines.append(f"{n} --[{edge['relation']}]--> {edge['target']}")
        return "\n".join(lines)

